// src/components/PriceManagementPage/PriceManagementPage.tsx
import React, { useState, useEffect } from 'react';
import { useProducts, Product } from '../context/ProductContext';
import EditablePriceTable from './EditablePriceTable';
import SearchBar from '../PriceManagementPage/SearchBar';
import './PriceManagementPage.css';

interface TableProduct {
    id: number;
    name: string;
    currentPrice: number;
}

export default function PriceManagementPage() {
    const { products, updateProductPriceAndStock, deleteProduct } = useProducts();

    const [searchResults, setSearchResults] = useState<TableProduct[]>([]);

    useEffect(() => {
        // initialize table from context
        setSearchResults(
            products.map((p) => ({
                id: p.id,
                name: p.name,
                currentPrice: p.price,
            }))
        );
    }, [products]);

    const handleSearch = (q: string) => {
        const lower = q.toLowerCase().trim();
        if (!lower) {
            setSearchResults(
                products.map((p) => ({
                    id: p.id,
                    name: p.name,
                    currentPrice: p.price,
                }))
            );
        } else {
            setSearchResults(
                products
                    .filter((p) => p.name.toLowerCase().includes(lower))
                    .map((p) => ({
                        id: p.id,
                        name: p.name,
                        currentPrice: p.price,
                    }))
            );
        }
    };

    const handlePriceUpdate = (id: number, newPrice: number) => {
        // find existing stock, use today’s date
        const prod = products.find((p) => p.id === id);
        if (!prod) return;
        const today = new Date().toISOString().slice(0, 10);
        updateProductPriceAndStock(id, newPrice, prod.stock, today);
    };

    return (
        <div className="price-management-container">
            <h2>Real-Time Pricing</h2>

            <SearchBar onSearch={handleSearch} placeholder="Ürün ara…" />

            <EditablePriceTable
                products={searchResults}
                onPriceUpdate={handlePriceUpdate}
                onDelete={(id) => deleteProduct(id)}
            />
        </div>
    );
}
